// ════════════════════════════════════════════════════════
// CFO MEMORY INGEST — Validate & Prepare v1.4
// v1.4 : pageContent = TEXTE BRUT UNIQUEMENT (zéro préfixe)
//   • [CFO-MEMORY | ...] supprimé du contenu vectorisé (c'était le bug BUG2)
//   • Contexte encodé dans metadata JSONB (non vectorisé par pgvector)
//   • 1 vecteur par entrée garanti (chunkSize=100000, overlap=0)
// ════════════════════════════════════════════════════════
const body = $input.first().json.body || $input.first().json;

const texte      = (body.texte || body.text || '').trim();
const categorie  = (body.categorie || body.category || 'general').toLowerCase();
const session_id = body.session_id || 'unknown';

const VALID_CATS = ['preference', 'regle', 'contexte', 'general'];

if (!texte || texte.length < 5) {
  throw new Error('Texte vide ou trop court (min 5 caractères).');
}
if (!VALID_CATS.includes(categorie)) {
  throw new Error('Catégorie invalide: ' + categorie + '. Autorisées: ' + VALID_CATS.join(', '));
}

// v1.4 : pageContent = texte PROPRE, sans aucun préfixe technique
// Les tokens [CFO-MEMORY], [PREFERENCE], [2026-04-28] ne doivent PAS
// être dans l'espace vectoriel — ils polluaient la similarité sémantique
const pageContent = texte;

// Metadata complète stockée en JSONB (colonne metadata, NON vectorisée)
const date_iso = new Date().toISOString().slice(0, 10);
return [{
  json: {
    pageContent,
    meta_categorie:    categorie,
    meta_source:       'cfo_agent_memory_writer',
    meta_date:         date_iso,
    meta_session:      session_id,
    meta_date_full:    new Date().toISOString()
  }
}];
